def generate_rainbow_table(password):
    rainbow_table = []
    for i in range(len(password)):
        rainbow_table.append([password[:i], password[i:]])
    return rainbow_table

def rainbow_table_attack(hashed_passwords, password):
    rainbow_table = generate_rainbow_table(password)
    for hashed_password in hashed_passwords:
        for entry in rainbow_table:
            if hashed_password == hash(entry[0]):
                return entry[0]
    return None

if __name__ == '__main__':
    hashed_passwords = ['hash123', 'hash456', 'hash789']
    password = 'password'
    print(rainbow_table_attack(hashed_passwords, password))
